2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // --- Empty / processing fee baseline ---
7	  it("quote with empty item list returns premium 5 (only the processing fee)", () => {
8	    expect(quote({ items: [], customerYears: 0, previousContracts: 0 })).toBe(5);
9	  });
10	
11	  // --- Base premiums for main items (with processing fee) ---
12	  it("quote for a single plain sword returns premium 105 (100 base + 5 fee)", () => {
13	    expect(
14	      quote({
15	        items: [{ type: "sword" }],
16	        customerYears: 0,
17	        previousContracts: 0,
18	      }),
19	    ).toBe(105);
20	  });
21	  it("quote for a single plain amulet returns premium 65 (60 base + 5 fee)", () => {
22	    expect(
23	      quote({
24	        items: [{ type: "amulet" }],
25	        customerYears: 0,
26	        previousContracts: 0,
27	      }),
28	    ).toBe(65);
29	  });
30	  it("quote for a single plain staff returns premium 85 (80 base + 5 fee)", () => {
31	    expect(
32	      quote({
33	        items: [{ type: "staff" }],
34	        customerYears: 0,
35	        previousContracts: 0,
36	      }),
37	    ).toBe(85);
38	  });
39	  it("quote for a single plain potion returns premium 45 (40 base + 5 fee)", () => {
40	    expect(
41	      quote({
42	        items: [{ type: "potion" }],
43	        customerYears: 0,
44	        previousContracts: 0,
45	      }),
46	    ).toBe(45);
47	  });
48	
49	  // --- Components and block-of-3 rule ---
50	  it("quote for 2 runes returns premium 55 (50 base + 5 fee)", () => {
51	    expect(
52	      quote({
53	        items: [{ type: "rune" }, { type: "rune" }],
54	        customerYears: 0,
55	        previousContracts: 0,
56	      }),
57	    ).toBe(55);
58	  });
59	  it("quote for 3 runes returns premium 65 (60 base block + 5 fee)", () => {
60	    expect(
61	      quote({
62	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }],
63	        customerYears: 0,
64	        previousContracts: 0,
65	      }),
66	    ).toBe(65);
67	  });
68	  it("quote for 4 runes returns premium 105 (100 base + 5 fee, no block — block requires exactly 3)", () => {
69	    expect(
70	      quote({
71	        items: [{ type: "rune" }, { type: "rune" }, { type: "rune" }, { type: "rune" }],
72	        customerYears: 0,
73	        previousContracts: 0,
74	      }),
75	    ).toBe(105);
76	  });
77	  it("quote for 7 runes returns premium 180 (175 base + 5 fee)", () => {
78	    expect(
79	      quote({
80	        items: [
81	          { type: "rune" },
82	          { type: "rune" },
83	          { type: "rune" },
84	          { type: "rune" },
85	          { type: "rune" },
86	          { type: "rune" },
87	          { type: "rune" },
88	        ],
89	        customerYears: 0,
90	        previousContracts: 0,
91	      }),
92	    ).toBe(180);
93	  });
94	  it("quote for 2 runes + 1 moonstone returns premium 80 (75 base + 5 fee, no block: different types)", () => {
95	    expect(
96	      quote({
97	        items: [{ type: "rune" }, { type: "rune" }, { type: "moonstone" }],
98	        customerYears: 0,
99	        previousContracts: 0,
100	      }),
101	    ).toBe(80);
102	  });
103	  it.todo("quote for 3 runes + 3 moonstones returns premium 125 (120 base + 5 fee, two separate blocks)");
104	
105	  // --- Item-specific modifiers ---
106	  it.todo("quote for a cursed sword (steel, ench 3) for newcomer (0 yrs, no previous) returns premium 165");
107	  it.todo("quote for a sword with enchantment exactly 5 applies the high-enchantment surcharge");
108	  it.todo("quote for a sword with enchantment 4 does not apply the high-enchantment surcharge");
109	  it.todo("quote for a cursed sword with enchantment 5 applies both curse and high-enchantment surcharges");
110	
111	  // --- Policy-wide modifiers ---
112	  it.todo("quote for a customer with exactly 2 years applies the 20% loyalty discount");
113	  it.todo("first quote in a scenario applies the 10% first-insurance surcharge");
114	  it.todo("second quote in a scenario applies the 15% follow-up contract discount");
115	
116	  // --- Modifier scope on multi-item policies ---
117	  it.todo("quote for cursed sword + plain amulet: curse surcharge is 50G (50% of cursed item's base, not policy total) → 215G (210 + 5 fee)");
118	
119	  // --- Rounding ---
120	  it.todo("premium calculation yielding 197.5 rounds up to 198 (in MHPCO's favor)");
121	
122	  // --- Integration: long-standing customer's second contract ---
123	  it.todo("quote for cursed sword (steel, ench 7) for 3-yr customer's second quote returns premium 160");
124	
125	  // --- Claim: standard reimbursement ---
126	  it.todo("claim on regular sword (steel, ench 3) with damage 500 → payout 400 (full minus 100 deductible)");
127	  it.todo("claim on a rune (insurance 250, no enchantment/material) with damage 200 → payout 100 (full minus deductible)");
128	
129	  // --- Claim: deductible per damage event ---
130	  it.todo("claim with damage to insured sword (500) and insured amulet (300) → payout 600 (deductible applies once per item)");
131	
132	  // --- Claim: enchantment threshold ---
133	  it.todo("claim on steel sword ench 9, damage 1000 → payout 400 (50% then deductible)");
134	
135	  // --- Claim: dragon material ---
136	  it.todo("claim on dragon-material sword ench 5, damage 800 → payout 700 (full reimbursement then deductible)");
137	
138	  // --- Claim: enchantment vs dragon material (50% rule wins) ---
139	  it.todo("claim on dragon-material sword ench 9, damage 1000 → payout 400 (50% rule wins, then deductible)");
140	  it.todo("claim on dragon-material sword ench 8, damage 1000 → payout 400 (high-enchantment clause applies, then deductible)");
141	
142	  // --- Claim: payout rounding ---
143	  it.todo("payout calculation yielding 350.5 rounds down to 350 (in MHPCO's favor)");
144	
145	  // --- Multiple items of the same type ---
146	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
147	  it.todo("dragon attack damaging both swords (two sword entries) treats each as separate damage with own deductible");
148	
149	  // --- Cap ---
150	  it.todo("policy covering sword + amulet has insurance sum 1600 and cap 3200");
151	  it.todo("cap is based on unmodified insurance value: cursed sword has cap 2000 regardless of premium modifiers");
152	  it.todo("policy covering sword + 3 runes has insurance sum 1750 (block discount affects premium only, not insurance sum)");
153	
154	  // --- Cap exhaustion across successive claims ---
155	  it.todo("sword (cap 2000): first claim 1500 → payout 1400, remaining cap 600");
156	  it.todo("sword (cap 2000): second claim 1500 after first → payout 600, remaining cap 0 (reduced to remaining cap)");
157	
158	  // --- Error cases ---
159	  it.todo("quote with unknown item type causes the CLI to exit with non-zero status and error to stderr");
160	  it.todo("claim referencing a damage entry whose item is not in the policy causes non-zero exit and stderr error");
161	  it.todo("claim with more damage entries of a type than insured (e.g. two sword damages, one sword) causes non-zero exit");
162	  it.todo("claim with a damage entry of negative amount causes non-zero exit and stderr error");
163	});
